//! Spec-compliance tests: Run Font Resolution & Style Cascade
//!
//! These tests audit font resolution through themes, cs/rtl activation of
//! complex script properties, cs font slot forcing, and style-defined
//! property cascade for position and kern.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/run-font-resolution/create_docs.py`.

use stemma::{InlineNode, Mark, MarkValue};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/run-font-resolution";

// -- helpers ----------------------------------------------------------------
fn text_nodes(p: &stemma::ParagraphNode) -> Vec<stemma::TextNode> {
    p.all_inlines_owned()
        .into_iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(*t),
            _ => None,
        })
        .collect()
}

// ── Test 1: Theme font resolves through cascade ────────────────────────

/// ECMA-376 §17.3.2.26: When a paragraph style specifies
/// asciiTheme="minorHAnsi", the resolved font should come from the theme's
/// minor latin font definition.
///
/// Fixture: theme defines minorHAnsi as "Calibri"; paragraph style
/// ThemeFontPara uses asciiTheme="minorHAnsi".
#[test]
fn spec_theme_font_resolves_through_cascade() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "theme-font-cascade");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Theme cascade text"))
        .expect("should find theme cascade paragraph");

    let nodes = text_nodes(p);
    let run = nodes
        .iter()
        .find(|n| n.text.contains("Theme cascade text"))
        .expect("should find theme cascade run");

    // The paragraph style's asciiTheme=minorHAnsi should resolve to "Calibri"
    // from the theme. The style resolver resolves theme references after
    // cascading through the style hierarchy (styles.rs resolve() post-processing).
    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Calibri"),
        "asciiTheme='minorHAnsi' from paragraph style should resolve to 'Calibri' \
         via theme font definitions. Got font_family={:?}. \
         ECMA-376 §17.3.2.26.",
        run.style_props.font_family
    );
}

// ── Test 2: cs/rtl activates complex script properties ─────────────────

/// ECMA-376 §17.3.2.7/§17.3.2.30: When cs is set on a run, bCs replaces b
/// for bold determination and iCs replaces i for italic determination.
///
/// Fixture: run with bCs=on, i=on, cs=on.
/// - Bold should come from bCs (on) since cs is active.
/// - The non-CS control run (bCs=on, i=on, NO cs) should be italic but not bold.
#[test]
fn spec_cs_rtl_activates_complex_script_properties() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-activation");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    // CS-activated run: bCs=on, i=on, cs=on
    let cs_run = nodes
        .iter()
        .find(|n| n.text.contains("CS activated run"))
        .expect("should find CS activated run");

    // With cs=on: bCs=on -> bold should be on
    assert!(
        cs_run.marks.contains(&Mark::Bold),
        "cs=on with bCs=on should produce Bold. Got marks: {:?}. \
         ECMA-376 §17.3.2.7.",
        cs_run.marks
    );

    // Control run: bCs=on, i=on, NO cs
    let control_run = nodes
        .iter()
        .find(|n| n.text.contains("Non-CS control run"))
        .expect("should find control run");

    // Without cs: bCs is ignored, b is absent -> not bold
    assert!(
        !control_run.marks.contains(&Mark::Bold),
        "Without cs, bCs=on should NOT produce Bold — bCs only applies \
         when cs/rtl is active. Got marks: {:?}.",
        control_run.marks
    );

    // Without cs: i=on applies normally -> italic
    assert!(
        control_run.marks.contains(&Mark::Italic),
        "Without cs, i=on should produce Italic. Got marks: {:?}.",
        control_run.marks
    );
}

/// ECMA-376 §17.3.2.30: When cs is active and iCs is absent, italic should
/// be suppressed — the CS properties completely replace the non-CS properties,
/// they do not fall back to the non-CS values.
#[test]
fn spec_cs_suppresses_non_cs_italic_when_ics_absent() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-activation");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let cs_run = nodes
        .iter()
        .find(|n| n.text.contains("CS activated run"))
        .expect("should find CS activated run");

    // Per spec, cs=on means iCs determines italic. iCs is absent (Inherit),
    // so italic should be off. But the resolver keeps i=on because it only
    // replaces italic when iCs is explicitly set.
    assert!(
        !cs_run.marks.contains(&Mark::Italic),
        "cs=on with only i=on (no iCs) should NOT produce Italic — \
         iCs is absent so italic should be off. Got marks: {:?}. \
         ECMA-376 §17.3.2.30.",
        cs_run.marks
    );
}

// ── Test 3: cs forces cs font slot ─────────────────────────────────────

/// MS-OI29500 §17.3.2.26(b): When cs is set, the cs font is used for ALL
/// characters regardless of Unicode range.
///
/// Fixture: run with ascii="Courier", cs="Arial", w:cs=on on English text.
/// The resolved font_family should be "Arial" (cs font), not "Courier".
#[test]
fn spec_cs_forces_cs_font_slot() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-forces-cs-font");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("CS font override text"))
        .expect("should find CS font override run");

    // With cs=on, font_family should be the cs font ("Arial"), not
    // the ascii font ("Courier").
    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Arial"),
        "cs=on should force cs font 'Arial' as font_family, not ascii font 'Courier'. \
         Got font_family={:?}. MS-OI29500 §17.3.2.26(b).",
        run.style_props.font_family
    );

    // Verify cs and font_cs are also set correctly
    assert_eq!(
        run.style_props.cs,
        MarkValue::On,
        "Run should have cs=On. Got cs={:?}.",
        run.style_props.cs
    );
    assert_eq!(
        run.style_props.font_cs.as_deref(),
        Some("Arial"),
        "font_cs should be 'Arial'. Got {:?}.",
        run.style_props.font_cs
    );
}

// ── Test 4: Style-defined position cascade ──────────────────────────────

/// ISO 29500-1 §17.3.2.24: The w:position element specifies vertical
/// displacement. When defined in a character style, it should cascade to
/// runs using that style.
#[test]
fn spec_style_defined_position_cascades_to_runs() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "style-position-cascade");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("Style position text"))
        .expect("should find style position run");

    // The character style RaisedChar defines position=24 (raised 12pt).
    // If parse_rpr_marks parsed w:position, the cascade would produce Some(24).
    assert_eq!(
        run.style_props.position,
        Some(24),
        "Character style defines position=24 but it did not cascade to the run. \
         Got position={:?}. This fails because parse_rpr_marks does not handle \
         w:position. ISO 29500-1 §17.3.2.19.",
        run.style_props.position
    );
}

// ── Test 5: Style-defined kern cascade ──────────────────────────────────

/// ISO 29500-1 §17.3.2.19(a): The w:kern element specifies the minimum
/// font size for automatic kerning. When defined in a character style, it
/// should cascade to runs using that style.
#[test]
fn spec_style_defined_kern_cascades_to_runs() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "style-kern-cascade");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("Style kern text"))
        .expect("should find style kern run");

    // The character style KernedChar defines kern=28 (14pt threshold).
    // If parse_rpr_marks parsed w:kern, the cascade would produce Some(28).
    assert_eq!(
        run.style_props.kern,
        Some(28),
        "Character style defines kern=28 but it did not cascade to the run. \
         Got kern={:?}. This fails because parse_rpr_marks does not handle \
         w:kern. ISO 29500-1 §17.3.2.19(a).",
        run.style_props.kern
    );
}

// ── Test 6: East Asian Times New Roman bypass ───────────────────────────

/// MS-OI29500 §2.1.88(d): If the eastAsia font is "Times New Roman" and
/// ascii == hAnsi, the ascii font replaces eastAsia for all characters.
///
/// Fixture: run with ascii=hAnsi="Calibri", eastAsia="Times New Roman".
/// After the bypass rule, font_east_asia should be "Calibri" (replaced),
/// and font_family should remain "Calibri".
#[test]
fn spec_east_asian_times_new_roman_bypass() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "east-asian-tnr-bypass");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("East Asian TNR bypass text"))
        .expect("should find east asian TNR bypass run");

    // font_family should be "Calibri" (from ascii/hAnsi)
    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Calibri"),
        "font_family should be 'Calibri' (ascii/hAnsi). Got {:?}.",
        run.style_props.font_family
    );

    // The bypass rule replaces eastAsia="Times New Roman"
    // with the ascii font, so font_east_asia should now be "Calibri".
    assert_eq!(
        run.style_props.font_east_asia.as_deref(),
        Some("Calibri"),
        "font_east_asia='Times New Roman' should be replaced with ascii font 'Calibri' \
         per MS-OI29500 §2.1.88(d) bypass rule. Got font_east_asia={:?}.",
        run.style_props.font_east_asia
    );
}
